const items = $input.all();

// ===== TẠO CSV =====
let csv = 'Order Code,Total Amount (VND),Status,Created At\n';

for (const item of items) {
  const row = item.json;
  csv += `${row.order_code || ''},${row.total_amount || 0},${row.status || ''},${row.created_at || ''}\n`;
}

// ===== TÍNH KPI =====
const totalOrders = items.length;
const totalRevenue = items.reduce((sum, item) => {
  return sum + Number(item.json.total_amount || 0);
}, 0);

const formattedRevenue = totalRevenue.toLocaleString('vi-VN');

// ===== HTML EMAIL =====
const emailHTML = `
<div style="font-family: Arial, sans-serif; max-width:600px; margin:auto; border:1px solid #ddd; border-radius:10px; padding:20px;">
  <h2 style="color:#1f2937;">📊 DAILY SALES REPORT</h2>

  <p><b>Ngày báo cáo:</b> ${new Date().toLocaleDateString('vi-VN')}</p>

  <div style="background:#f3f4f6; padding:15px; border-radius:8px; margin:15px 0;">
    <p>🧾 <b>Tổng đơn:</b> ${totalOrders}</p>
    <p>💰 <b>Doanh thu:</b> ${formattedRevenue} VND</p>
  </div>

  <p>📎 File chi tiết được đính kèm dưới dạng CSV, có thể mở bằng Excel.</p>

  <hr/>

  <p style="color:gray; font-size:12px;">
    ⚙️ Generated automatically by <b>DashAuto Automation System</b>
  </p>
</div>
`;

// ===== TRẢ OUTPUT CHO NODE SAU =====
return [
  {
    json: {
      total_orders: totalOrders,
      total_revenue: totalRevenue,
      email_subject: '📊 Daily Sales Report - DashAuto',
      email_body: emailHTML,
      report_title: 'Bao cao tu dong hang ngay',
      report_type: 'daily',
      report_content: `Tong don: ${totalOrders} | Doanh thu: ${formattedRevenue} VND`,
      email_status: 'success',
    },
    binary: {
      data: {
        data: Buffer.from(csv).toString('base64'),
        mimeType: 'text/csv',
        fileName: `daily_report_${new Date().toISOString().slice(0, 10)}.csv`,
      },
    },
  },
];
